ym_map  = {b[0]: b[1] for b in ym_raw}
rty_map = {b[0]: b[1] for b in rty_raw}
zn_map  = {b[0]: b[1] for b in zn_raw}
gc_map  = {b[0]: b[1] for b in gc_raw}

common_ts = sorted(set(mnq_map) & set(es_map) & set(ym_map) &
                   set(rty_map) & set(zn_map) & set(gc_map))

mnq_o  = [mnq_map[t][1] for t in common_ts]
mnq_h  = [mnq_map[t][2] for t in common_ts]
mnq_l  = [mnq_map[t][3] for t in common_ts]
mnq_c  = [mnq_map[t][4] for t in common_ts]
es_c   = [es_map[t]  for t in common_ts]
ym_c   = [ym_map[t]  for t in common_ts]
rty_c  = [rty_map[t] for t in common_ts]
