gc_c   = [gc_map[t]  for t in common_ts]

N = len(common_ts)
print(f"Common bars: {N}")

mnq_h_a = np.array(mnq_h, dtype=float)
mnq_l_a = np.array(mnq_l, dtype=float)
mnq_c_a = np.array(mnq_c, dtype=float)

# ═══════════════════════════════════════════════════════════════════════════
# ATR-14 (Wilder)
# ═══════════════════════════════════════════════════════════════════════════
def compute_atr14(h, l, c):
    n = len(c)
    tr = np.zeros(n)
    tr[0] = h[0] - l[0]
    for i in range(1, n):
        tr[i] = max(h[i]-l[i], abs(h[i]-c[i-1]), abs(l[i]-c[i-1]))
    atr = np.zeros(n)
    atr[13] = float(np.mean(tr[:14]))
    for i in range(14, n):
        atr[i] = (atr[i-1] * 13.0 + tr[i]) / 14.0
    return atr

atr14 = compute_atr14(mnq_h_a, mnq_l_a, mnq_c_a)

# ═══════════════════════════════════════════════════════════════════════════
# LOG RETURNS
# ═══════════════════════════════════════════════════════════════════════════
def log_ret(prices):
    p = np.array(prices, dtype=float)
    r = np.zeros(len(p))
    mask = p[:-1] > 0
    r[1:][mask] = np.log(p[1:][mask] / p[:-1][mask])
    return r

r_mnq = log_ret(mnq_c)
r_es  = log_ret(es_c)
r_ym  = log_ret(ym_c)
r_rty = log_ret(rty_c)
r_zn  = log_ret(zn_c)
r_gc  = log_ret(gc_c)

factors = [r_es, r_ym, r_rty, r_zn, r_gc]
K = 5

# ═══════════════════════════════════════════════════════════════════════════
# PCA SIGNAL
# ═══════════════════════════════════════════════════════════════════════════
def compute_signals(H, RL, SM, CB):
    disloc = np.zeros(N)

    for i in range(H, N):
        w_mnq = r_mnq[i-H:i]
        std_mnq = np.std(w_mnq, ddof=0)
        if std_mnq < 1e-12:
            continue
        pred = 0.0
        for k in range(K):
            w_f = factors[k][i-H:i]
            std_f = np.std(w_f, ddof=0)
            if std_f < 1e-12:
                continue
            corr = float(np.corrcoef(w_mnq, w_f)[0, 1])
            beta = corr * std_mnq / std_f
            pred += beta * factors[k][i]
        disloc[i] = r_mnq[i] - pred

    sigma_D = np.zeros(N)
    for i in range(RL, N):
        sigma_D[i] = np.std(disloc[i-RL:i], ddof=0)

    start = max(H, RL)
    fs  = np.zeros(N, dtype=int)
    for i in range(start, N):
        if sigma_D[i] < 1e-12:
            continue
        if disloc[i] < -SM * sigma_D[i]:
            fs[i] = 1
        elif disloc[i] > SM * sigma_D[i]:
            fs[i] = -1

    stk = np.zeros(N, dtype=int)
    cs  = np.zeros(N, dtype=int)
    for i in range(1, N):
        if fs[i] != 0 and fs[i] == fs[i-1]:
            stk[i] = stk[i-1] + 1
        elif fs[i] != 0:
            stk[i] = 1
        else:
            stk[i] = 0
        cs[i] = fs[i] if stk[i] >= CB else 0

    return cs

# ═══════════════════════════════════════════════════════════════════════════
# BACKTEST
# ═══════════════════════════════════════════════════════════════════════════
TICK = 0.25
MULT = 2.0
COMM = 0.35
SLIP = TICK

def backtest(H, RL, SM, CB, MH, SL, RR, initial_capital=100_000):
    cs = compute_signals(H, RL, SM, CB)

    equity   = float(initial_capital)
    peak_eq  = equity
    max_dd   = 0.0
    pnls     = []

    pos       = 0
    entry_px  = 0.0
    sl_px     = 0.0
    tp_px     = 0.0
    bars_held = 0

    for i in range(1, N):
        if pos != 0:
            bars_held += 1
            exit_px  = mnq_c_a[i]
            do_exit  = False

            if pos == 1:
                if mnq_l_a[i] <= sl_px:
                    exit_px = sl_px; do_exit = True
                elif mnq_h_a[i] >= tp_px:
                    exit_px = tp_px; do_exit = True
                elif bars_held >= MH:
                    do_exit = True
            else:
                if mnq_h_a[i] >= sl_px:
                    exit_px = sl_px; do_exit = True
                elif mnq_l_a[i] <= tp_px:
                    exit_px = tp_px; do_exit = True
                elif bars_held >= MH:
                    do_exit = True

            if do_exit:
                net_pnl = pos * (exit_px - entry_px) * MULT - 2 * COMM
                pnls.append(net_pnl)
                equity += net_pnl
                if equity > peak_eq:
                    peak_eq = equity
                dd = (peak_eq - equity) / peak_eq if peak_eq > 0 else 0.0
                if dd > max_dd:
                    max_dd = dd
                pos = 0

        if pos == 0 and cs[i] != 0:
            if atr14[i] < 1e-6:
                continue
            pos       = cs[i]
            entry_px  = mnq_c_a[i] + pos * SLIP
            sl_dist   = atr14[i] * SL
            tp_dist   = sl_dist * RR
            sl_px     = entry_px - pos * sl_dist
            tp_px     = entry_px + pos * tp_dist
            bars_held = 0

    n_trades = len(pnls)
    if n_trades == 0:
        return dict(sharpe=0.0, net_pnl=0.0, win_rate=0.0,
                    n_trades=0, profit_factor=0.0, max_dd=0.0)

    arr      = np.array(pnls)
    net_pnl  = float(arr.sum())
    wins     = arr[arr > 0]
    losses   = arr[arr <= 0]
    win_rate = len(wins) / n_trades
    gw = float(wins.sum()) if len(wins) else 0.0
    gl = float(abs(losses.sum())) if len(losses) else 0.0
    pf = gw / gl if gl > 0 else 999.0

    std = float(arr.std(ddof=0))
    sharpe = (float(arr.mean()) / std * math.sqrt(252 * 6.5)) if std > 0 else 0.0

    return dict(sharpe=sharpe, net_pnl=net_pnl, win_rate=win_rate,
                n_trades=n_trades, profit_factor=pf, max_dd=max_dd)

# ═══════════════════════════════════════════════════════════════════════════
# DIAGNOSTIC: does flipping signal direction (momentum) beat mean-reversion?
# ═══════════════════════════════════════════════════════════════════════════
def backtest_momentum(H, RL, SM, CB, MH, SL, RR, initial_capital=100_000):
    """Same as backtest() but signal direction reversed (momentum, not mean-rev)."""
    cs_mr = compute_signals(H, RL, SM, CB)
    cs = -cs_mr   # flip: disloc up → long, disloc down → short

    equity   = float(initial_capital)
    peak_eq  = equity
    max_dd   = 0.0
    pnls     = []

    pos = 0; entry_px = 0.0; sl_px = 0.0; tp_px = 0.0; bars_held = 0

    for i in range(1, N):
        if pos != 0:
            bars_held += 1
            exit_px = mnq_c_a[i]; do_exit = False
            if pos == 1:
                if mnq_l_a[i] <= sl_px: exit_px = sl_px; do_exit = True
                elif mnq_h_a[i] >= tp_px: exit_px = tp_px; do_exit = True
                elif bars_held >= MH: do_exit = True
            else:
                if mnq_h_a[i] >= sl_px: exit_px = sl_px; do_exit = True
                elif mnq_l_a[i] <= tp_px: exit_px = tp_px; do_exit = True
                elif bars_held >= MH: do_exit = True
            if do_exit:
                net_pnl = pos * (exit_px - entry_px) * MULT - 2 * COMM
                pnls.append(net_pnl); equity += net_pnl
                if equity > peak_eq: peak_eq = equity
                dd = (peak_eq - equity) / peak_eq if peak_eq > 0 else 0.0
                if dd > max_dd: max_dd = dd
                pos = 0
        if pos == 0 and cs[i] != 0:
            if atr14[i] < 1e-6: continue
            pos = cs[i]; entry_px = mnq_c_a[i] + pos * SLIP
            sl_dist = atr14[i] * SL; tp_dist = sl_dist * RR
            sl_px = entry_px - pos * sl_dist; tp_px = entry_px + pos * tp_dist
            bars_held = 0

    n_trades = len(pnls)
    if n_trades == 0:
        return dict(sharpe=0.0, net_pnl=0.0, win_rate=0.0,
                    n_trades=0, profit_factor=0.0, max_dd=0.0)
    arr = np.array(pnls)
    wins = arr[arr > 0]; losses = arr[arr <= 0]
    win_rate = len(wins) / n_trades
    gw = float(wins.sum()) if len(wins) else 0.0
    gl = float(abs(losses.sum())) if len(losses) else 0.0
    pf = gw / gl if gl > 0 else 999.0
    std = float(arr.std(ddof=0))
    sharpe = (float(arr.mean()) / std * math.sqrt(252 * 6.5)) if std > 0 else 0.0
    return dict(sharpe=sharpe, net_pnl=float(arr.sum()), win_rate=win_rate,
                n_trades=n_trades, profit_factor=pf, max_dd=max_dd)

